import React, { useState, useEffect } from 'react';
import FileExplorer from './FileExplorer';
import MicrosoftTeams from './MicrosoftTeams';
import MicrosoftWord from './MicrosoftWord';
import MicrosoftExcel from './MicrosoftExcel';
import PowerPoint from './PowerPoint';
import PDFReader from './PDF';
import Chrome from './chrome';
import Zoom from './Zoom';
import WhatsApp from './WhatsApp';
import Skype from './Skype';  // Importă componenta Skype
import axios from 'axios';

import TeamsIcon from '../assets/icons_sidebar/business.png';
import WordIcon from '../assets/icons_sidebar/word.png';
import ExcelIcon from '../assets/icons_sidebar/excel.png';
import PowerPointIcon from '../assets/icons_sidebar/office.png';
import ChromeIcon from '../assets/icons_sidebar/chrome.png';
import PdfIcon from '../assets/icons_sidebar/acrobat.png';
import FileExplorerIcon from '../assets/icons_sidebar/folder.png';
import ZoomIcon from '../assets/icons_sidebar/zoom.png';
import WhatsappIcon from '../assets/icons_sidebar/whatsapp.png';
import SkypeIcon from '../assets/icons_sidebar/skype.png';  // Icon pentru Skype
import LogoIcon from '../assets/logo/logo3.png'; 

import '../assets/styles/Sidebar.css';

const Sidebar = () => {
  const [activeComponent, setActiveComponent] = useState('fileExplorer');
  const [showFileExplorer, setShowFileExplorer] = useState(true);
  const [backendUrl, setBackendUrl] = useState('');
  const [serverInfo, setServerInfo] = useState({ ip: '', port: '' });

  useEffect(() => {
    fetchBackendUrl();
  }, []);

  const fetchBackendUrl = async () => {
    try {
      const response = await axios.get('/api/server-info');
      const { ip, port } = response.data;
      const url = `http://${ip}:${port}`;
      setBackendUrl(url);
      setServerInfo({ ip, port });
    } catch (error) {
      console.error('There was an error fetching the backend URL!', error);
    }
  };

  const handleFileExplorerClick = () => {
    setActiveComponent('fileExplorer');
    setShowFileExplorer(true);
  };

  const handleMicrosoftTeamsClick = () => {
    setActiveComponent('microsoftTeams');
    axios.post(`${backendUrl}/shortcuts/teams/open-teams/`)
      .then(response => {
        console.log(response.data.message || 'Microsoft Teams opened successfully');
      })
      .catch(error => {
        console.error('There was an error opening Microsoft Teams!', error);
      });
  };

  const handleMicrosoftWordClick = () => {
    setActiveComponent('microsoftWord');
    axios.post(`${backendUrl}/shortcuts/word/open-word/`)
      .then(response => {
        console.log(response.data.message || 'Microsoft Word opened successfully');
      })
      .catch(error => {
        console.error('There was an error opening Microsoft Word!', error);
      });
  };

  const handleMicrosoftExcelClick = () => {
    setActiveComponent('microsoftExcel');
    axios.post(`${backendUrl}/shortcuts/excel/open-excel/`)
      .then(response => {
        console.log(response.data.message || 'Microsoft Excel opened successfully');
      })
      .catch(error => {
        console.error('There was an error opening Microsoft Excel!', error);
      });
  };

  const handlePowerPointClick = () => {
    setActiveComponent('powerPoint');
    axios.post(`${backendUrl}/shortcuts/powerpoint/open-powerpoint/`)
      .then(response => {
        console.log(response.data.message || 'Microsoft PowerPoint opened successfully');
      })
      .catch(error => {
        console.error('There was an error opening Microsoft PowerPoint!', error);
      });
  };

  const handlePdfReaderClick = () => {
    setActiveComponent('pdfReader');
    axios.post(`${backendUrl}/shortcuts/pdf/open-acrobat/`)
      .then(response => {
        console.log(response.data.message || 'Adobe Acrobat opened successfully');
      })
      .catch(error => {
        console.error('There was an error opening Adobe Acrobat!', error);
      });
  };

  const handleChromeClick = () => {
    setActiveComponent('chrome');
    axios.post(`${backendUrl}/shortcuts/chrome/open-chrome/`)
      .then(response =>{
        console.log(response.data.message || 'Chrome opened successfully');
      })
      .catch(error =>{
        console.error('There was an error opening chrome!', error);
      });
  };

  const handleZoomClick = () => {
    setActiveComponent('zoom');
    axios.post(`${backendUrl}/shortcuts/zoom/open-zoom/`)
      .then(response => {
        console.log(response.data.message || 'Zoom opened successfully');
      })
      .catch(error => {
        console.error('There was an error opening Zoom!', error);
      });
  };

  const handleWhatsappClick = () => {
    setActiveComponent('whatsapp');
    axios.post(`${backendUrl}/shortcuts/whatsapp/open-whatsapp/`)
      .then(response => {
        console.log(response.data.message || 'WhatsApp opened successfully');
      })
      .catch(error => {
        console.error('There was an error opening WhatsApp!', error);
      });
  };

  const handleSkypeClick = () => {
    setActiveComponent('skype');
    axios.post(`${backendUrl}/shortcuts/skype/open-skype/`)
      .then(response => {
        console.log(response.data.message || 'Skype opened successfully');
      })
      .catch(error => {
        console.error('There was an error opening Skype!', error);
      });
  };

  const handleClose = () => {
    setActiveComponent(null);
    setShowFileExplorer(false);
  };

  return (
    <div className="app-container">

      <div className="sidebar">
        <div className="sidebar-header">
          <img src={LogoIcon} alt="My Shortcuts Logo" className="logo-icon" />
          <h2 className="sidebar-title">InfoVision SDG</h2>
        </div>
        <button className="sidebar-button" onClick={handleFileExplorerClick}>
          <img src={FileExplorerIcon} alt="File Explorer" className="icon" />
          File Explorer
        </button>
        <button className="sidebar-button" onClick={handleMicrosoftTeamsClick}>
          <img src={TeamsIcon} alt="Microsoft Teams" className="icon" />
          Microsoft Teams
        </button>
        <button className="sidebar-button" onClick={handleMicrosoftWordClick}>
          <img src={WordIcon} alt="Microsoft Word" className="icon" />
          Microsoft Word
        </button>
        <button className="sidebar-button" onClick={handleMicrosoftExcelClick}>
          <img src={ExcelIcon} alt="Microsoft Excel" className="icon" />
          Microsoft Excel
        </button>
        <button className="sidebar-button" onClick={handlePowerPointClick}>
          <img src={PowerPointIcon} alt="PowerPoint" className="icon" />
          PowerPoint
        </button>
        <button className="sidebar-button" onClick={handlePdfReaderClick}>
          <img src={PdfIcon} alt="PDF Reader" className="icon" />
          PDF Reader
        </button>
        <button className="sidebar-button" onClick={handleChromeClick}>
          <img src={ChromeIcon} alt="Chrome" className="icon" />
          Chrome
        </button>
        <button className="sidebar-button" onClick={handleZoomClick}>
          <img src={ZoomIcon} alt="Zoom" className="icon" />
          Zoom
        </button>
        <button className="sidebar-button" onClick={handleWhatsappClick}>
          <img src={WhatsappIcon} alt="WhatsApp" className="icon" />
          WhatsApp
        </button>
        <button className="sidebar-button" onClick={handleSkypeClick}>
          <img src={SkypeIcon} alt="Skype" className="icon" />
          Skype
        </button>
        <div className="copyright">
          &copy; 2024-SDG
        </div>
      </div>
      <div className="content">
        {activeComponent === 'fileExplorer' && (
          <FileExplorer showFileExplorer={showFileExplorer} setShowFileExplorer={setShowFileExplorer} setActiveComponent={setActiveComponent} onClose={handleClose} />
        )}
        {activeComponent === 'microsoftTeams' && <MicrosoftTeams onClose={handleClose} />}
        {activeComponent === 'microsoftWord' && <MicrosoftWord onClose={handleClose} />}
        {activeComponent === 'microsoftExcel' && <MicrosoftExcel onClose={handleClose} />}
        {activeComponent === 'powerPoint' && <PowerPoint onClose={handleClose} />}
        {activeComponent === 'pdfReader' && <PDFReader onClose={handleClose} />}
        {activeComponent === 'chrome' && <Chrome onClose={handleClose} />}
        {activeComponent === 'zoom' && <Zoom onClose={handleClose} />}
        {activeComponent === 'whatsapp' && <WhatsApp onClose={handleClose} />}
        {activeComponent === 'skype' && <Skype onClose={handleClose} />}
      </div>
      <div className="server-info">
        <p>IP Server: {serverInfo.ip}</p>
        <p>Port: {serverInfo.port}</p>
      </div>
    </div>
  );
};

export default Sidebar;
